#include <stdio.h>

int main() {
    int num = 50;
    int *ptr = &num;  // ptr এখন num এর অ্যাড্রেস ধারণ করছে

    printf("num এর মান: %d\n", num);
    printf("num এর অ্যাড্রেস: %p\n", &num);
    printf("ptr এর মাধ্যমে মান: %d\n", *ptr); // ডিরেফারেন্স করা

    *ptr = 100; // পয়েন্টার দিয়ে মূল ভ্যারিয়েবল পরিবর্তন
    printf("num এর নতুন মান: %d\n", num); // 100

    return 0;
}

void swap(int *a, int *b) {
    int temp = *a;
    *a = *b;
    *b = temp;
}

int main() {
    int x = 5, y = 10;
    swap(&x, &y);
    printf("x = %d, y = %d\n", x, y); // x = 10, y = 5
    return 0;
}
